PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT((?coll_span - ?rich_span) AS ?difference) WHERE {
  {
    SELECT(MAX(?coll_year) AS ?coll_max)(MIN(?coll_year) AS ?coll_min) WHERE {
      wd:Q249679 wdt:P3450 ?season .
      ?season wdt:P585 ?coll_year .
    }
  }
  {
    SELECT(MAX(?rich_year) AS ?rich_max)(MIN(?rich_year) AS ?rich_min) WHERE {
      wd:Q2521385 wdt:P3450 ?season .
      ?season wdt:P585 ?rich_year .
    }
  }
  BIND(?coll_max - ?coll_min AS ?coll_span)
  BIND(?rich_max - ?rich_min AS ?rich_span)
}

